   643→int nfp_net_pci_probe(struct nfp_pf *pf)
   644→{
   645→	struct devlink *devlink = priv_to_devlink(pf);
   646→	struct nfp_net_fw_version fw_ver;
   647→	u8 __iomem *ctrl_bar, *qc_bar;
