   655→			pf->fw_loaded ? "symbol table" : "firmware found");
   656→		return -EINVAL;
   657→	}
   658→
   659→	pf->max_data_vnics = nfp_net_pf_get_num_ports(pf);
   660→	if ((int)pf->max_data_vnics < 0)
   661→		return pf->max_data_vnics;
