   704→	err = nfp_shared_buf_register(pf);
   705→	if (err)
   706→		goto err_devlink_unreg;
   707→
   708→	err = nfp_devlink_params_register(pf);
   709→	if (err)
   710→		goto err_shared_buf_unreg;
   711→
   712→	mutex_lock(&pf->lock);
   713→	pf->ddir = nfp_net_debugfs_device_add(pf->pdev);
   714→
   715→	/* Allocate the vnics and do basic init */
   716→	err = nfp_net_pf_alloc_vnics(pf, ctrl_bar, qc_bar, stride);
   717→	if (err)
