   719→
   720→	err = nfp_net_pf_alloc_irqs(pf);
   721→	if (err)
   722→		goto err_free_vnics;
   723→
   724→	err = nfp_net_pf_app_start(pf);
   725→	if (err)
   726→		goto err_free_irqs;
   727→
   728→	err = nfp_net_pf_init_vnics(pf);
   729→	if (err)
   730→		goto err_stop_app;
